"use client"

import { createContext, useContext, useState, ReactNode, useCallback } from 'react'

export type Region = 'USA' | 'MX' | 'LATAM' | 'EU'
export type Currency = 'USD' | 'MXN' | 'EUR'

interface CurrencyContextType {
  region: Region
  currency: Currency
  exchangeRate: number
  setRegion: (region: Region) => void
  formatPrice: (priceUSD: number) => string
  convertPrice: (priceUSD: number) => number
}

const exchangeRates: Record<Currency, number> = {
  USD: 1,
  MXN: 17.50,
  EUR: 0.92
}

const regionToCurrency: Record<Region, Currency> = {
  USA: 'USD',
  MX: 'MXN',
  LATAM: 'MXN',
  EU: 'EUR'
}

const currencySymbols: Record<Currency, string> = {
  USD: '$',
  MXN: '$',
  EUR: '€'
}

const CurrencyContext = createContext<CurrencyContextType | undefined>(undefined)

export function CurrencyProvider({ children }: { children: ReactNode }) {
  const [region, setRegionState] = useState<Region>('LATAM')
  
  const currency = regionToCurrency[region]
  const exchangeRate = exchangeRates[currency]

  const setRegion = useCallback((newRegion: Region) => {
    setRegionState(newRegion)
  }, [])

  const convertPrice = useCallback((priceUSD: number) => {
    return priceUSD * exchangeRate
  }, [exchangeRate])

  const formatPrice = useCallback((priceUSD: number) => {
    const converted = convertPrice(priceUSD)
    const symbol = currencySymbols[currency]
    
    if (currency === 'MXN') {
      return `${symbol}${converted.toFixed(2)} MXN`
    }
    if (currency === 'EUR') {
      return `${converted.toFixed(2)}${symbol}`
    }
    return `${symbol}${converted.toFixed(2)}`
  }, [currency, convertPrice])

  return (
    <CurrencyContext.Provider value={{
      region,
      currency,
      exchangeRate,
      setRegion,
      formatPrice,
      convertPrice
    }}>
      {children}
    </CurrencyContext.Provider>
  )
}

export function useCurrency() {
  const context = useContext(CurrencyContext)
  if (!context) {
    throw new Error('useCurrency must be used within a CurrencyProvider')
  }
  return context
}

export const regions: { id: Region; name: string; flag: string }[] = [
  { id: 'USA', name: 'Estados Unidos', flag: '🇺🇸' },
  { id: 'MX', name: 'México', flag: '🇲🇽' },
  { id: 'LATAM', name: 'Latinoamérica', flag: '🌎' },
  { id: 'EU', name: 'Europa', flag: '🇪🇺' },
]
